examples.code:
// Initial State
RuleBase = [
 R1: IF X AND Y THEN Z,
 R2: IF Z THEN W,
 R3: IF W THEN V
]

// Iteration 1
WorkingMemory = {X, Y}
Matched: R1 (X and Y satisfied)
Fire R1 → Add Z to WM

// Iteration 2
WorkingMemory = {X, Y, Z}
Matched: R2 (Z satisfied)
Fire R2 → Add W to WM

// Iteration 3
WorkingMemory = {X, Y, Z, W}
Matched: R3 (W satisfied)
Fire R3 → Add V to WM

// Iteration 4
WorkingMemory = {X, Y, Z, W, V}
Matched: None (no new conditions)
Terminate

// Final Derived Facts: {Z, W, V}
